using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetSettings()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { EnableCaching = true, EnableLogging = true }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Generates a personalized greeting message.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name,
        [Description("Optional greeting style: formal or casual")] string style = "casual")
    {
        return style.ToLowerInvariant() switch
        {
            "formal" => $"Good day, {name}. It is a pleasure to make your acquaintance.",
            _ => $"Hey {name}! 👋 Welcome aboard!"
        };
    }
}

